import { Injectable } from '@angular/core';
import { Persistencelistener } from './persistencelistener';

@Injectable({
  providedIn: 'root',
})
export class Mappersistenceservice {

  private _listeners: Persistencelistener[];
  public get listeners(): Persistencelistener[] {
    return this._listeners;
  }
  public set listeners(value: Persistencelistener[]) {
    this._listeners = value;
  }

  constructor() { this.listeners = []; }

  save() {
    // console.log("PersistenceService SAVE called");
    this.listeners.forEach(listener => {
      listener.save();
    });
  }

  load() {
    // console.log("PersistenceService LOAD called");
    this.listeners.forEach(listener => {
      listener.load();
    });
  }

  clearAll(){
    this.listeners.forEach(listener => {
      listener.clear();
    });
  }
}
